import { readFile, writeFile } from "node:fs/promises";

const sources = [
  "src/data/mockPlants.js",
  "src/services/db.js",
  "src/services/gemini.js"
];

function stripExports(source) {
  return source
    .replaceAll("export const ", "const ")
    .replaceAll("export async function ", "async function ")
    .replaceAll("export function ", "function ");
}

function stripImports(source) {
  return source.replace(/import[\s\S]*?from\s+["'][^"']+["'];\s*/g, "");
}

const parts = [];
for (const file of sources) {
  parts.push(stripExports(await readFile(file, "utf8")));
}

const app = stripImports(await readFile("src/app.js", "utf8"));
parts.push(app);

await writeFile(
  "src/app.bundle.js",
  `/* Generated by scripts/build-bundle.mjs. Edit source modules, not this file. */\n${parts.join("\n\n")}\n`,
  "utf8"
);

console.log("Generated src/app.bundle.js");
